INSERT INTO t_p57647769_pwa_login_app.admin_tasks (assignee, status, comment, note) VALUES
('Я', 'open',
 'Документ 1: Публичная оферта (Пользовательское соглашение) — на сайт',
 'Публичный документ на сайте. Что за сервис, права/обязанности сторон, ответственность, статус сервиса-конструктора (помогаем обработать данные пользователя; налоги, платёжные системы, госорганы — пользователь делает сам, мы не налоговый/платёжный агент). Доступ: ознакомительный до оплаты, далее по тарифу. Акцепт = начало использования. К оферте приложить файл-заготовку текста.'),
('Я', 'open',
 'Документ 2: Политика обработки персональных данных — на сайт',
 'Отдельный публичный документ (152-ФЗ), на него ссылаются оферта и согласие. Перечень ПДн, цели обработки, сроки хранения, права субъекта. Общие меры защиты — в оферте, детали (шифрование, бэкапы, доступ) — во внутренней политике безопасности. К задаче приложить файл-заготовку.'),
('Я', 'open',
 'Документ 3: Согласие на обработку ПДн + Соглашение об использовании ПЭП (вход в приложение)',
 'Принимается при входе в приложение подтверждением по СМС = ПЭП (63-ФЗ). СМС-код — аналог собственноручной подписи. ВАЖНО: технически логировать факт подписания (номер телефона, время, код/хэш, версия документа). Пакет: согласие на ПДн + соглашение о ПЭП + присоединение к оферте в один клик. Приложить файл-заготовку.'),
('Я', 'open',
 'Документ 4: Тарифы и условия оплаты (при оплате тарифа)',
 'Принимается при оплате (оплата = акцепт). Суммы, порядок оплаты, продление, возвраты, состав тарифа. Можно оформить как соглашение об оказании платных услуг / приложение к оферте. Приложить файл-заготовку.');